func transcriptEventClass(kind string) string {
	switch kind {
	case "reasoning":
		return "text-gray-500"
	case "tool":
		return "text-indigo-400"
	case "text":
		return "text-green-300"
	case "stderr":
		return "text-red-400"
	case "step", "event", "raw":
		return "text-gray-400"
	default:
		return "text-gray-400"
	}
}

